# Exempel med fel ordning på satser, 
# vi borde egentligen få A

betyg = 95

if betyg >= 50:
    print("Du fick betyget E")
elif betyg >= 60: 
    print("Du fick betyget D")
elif betyg >= 70:
    print("Du fick betyget C")
elif betyg >= 80:
    print("Du fick betyget B")
elif betyg >= 90:
    print("Du fick betyget A")
else:
    print("Du fick betyget F")
